import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.CHQlKclR.js";const m=JSON.parse('{"title":"Odometry & Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"api/odom.md","filePath":"api/odom.md"}'),i={name:"api/odom.md"};function s(n,e,d,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="odometry-tracking" tabindex="-1">Odometry &amp; Tracking <a class="header-anchor" href="#odometry-tracking" aria-label="Permalink to &quot;Odometry &amp; Tracking&quot;">​</a></h1><p>The <code>vortex::Drive</code> class implements a high-frequency odometry task that maintains the robot&#39;s absolute position using any combination of motor encoders, rotation sensors, or the ADI.</p><h2 id="global-pose" tabindex="-1">Global Pose <a class="header-anchor" href="#global-pose" aria-label="Permalink to &quot;Global Pose&quot;">​</a></h2><p>These methods allow you to interact with the robot&#39;s internal coordinate system.</p><h3 id="odom-pose-set-double-x-double-y-double-theta" tabindex="-1"><code>odom_pose_set(double x, double y, double theta)</code> <a class="header-anchor" href="#odom-pose-set-double-x-double-y-double-theta" aria-label="Permalink to &quot;`odom_pose_set(double x, double y, double theta)`&quot;">​</a></h3><p>Teleports the robot to an exact start position.</p><ul><li><strong>x</strong>: X coordinate (inches).</li><li><strong>y</strong>: Y coordinate (inches).</li><li><strong>theta</strong>: Global heading (degrees).</li></ul><h3 id="odom-pose-get" tabindex="-1"><code>odom_pose_get()</code> <a class="header-anchor" href="#odom-pose-get" aria-label="Permalink to &quot;`odom_pose_get()`&quot;">​</a></h3><p>Returns a <code>vortex::pose</code> struct containing the current <code>x</code>, <code>y</code>, and <code>theta</code>.</p><hr><h2 id="tracking-wheel-configuration" tabindex="-1">Tracking Wheel Configuration <a class="header-anchor" href="#tracking-wheel-configuration" aria-label="Permalink to &quot;Tracking Wheel Configuration&quot;">​</a></h2><p>Vortex is sensor-agnostic. You can configure up to four tracking wheels for maximum accuracy.</p><h3 id="odom-tracker-left-set-vortex-tracking-wheel-tracker" tabindex="-1"><code>odom_tracker_left_set(vortex::tracking_wheel* tracker)</code> <a class="header-anchor" href="#odom-tracker-left-set-vortex-tracking-wheel-tracker" aria-label="Permalink to &quot;`odom_tracker_left_set(vortex::tracking_wheel* tracker)`&quot;">​</a></h3><p>Assigns a <code>tracking_wheel</code> object as the primary left-side horizontal sensor.</p><h3 id="odom-tracker-right-set-vortex-tracking-wheel-tracker" tabindex="-1"><code>odom_tracker_right_set(vortex::tracking_wheel* tracker)</code> <a class="header-anchor" href="#odom-tracker-right-set-vortex-tracking-wheel-tracker" aria-label="Permalink to &quot;`odom_tracker_right_set(vortex::tracking_wheel* tracker)`&quot;">​</a></h3><p>Assigns a <code>tracking_wheel</code> object as the secondary right-side horizontal sensor.</p><h3 id="odom-tracker-front-set-vortex-tracking-wheel-tracker-odom-tracker-back-set" tabindex="-1"><code>odom_tracker_front_set(vortex::tracking_wheel* tracker)</code> / <code>odom_tracker_back_set()</code> <a class="header-anchor" href="#odom-tracker-front-set-vortex-tracking-wheel-tracker-odom-tracker-back-set" aria-label="Permalink to &quot;`odom_tracker_front_set(vortex::tracking_wheel* tracker)` / `odom_tracker_back_set()`&quot;">​</a></h3><p>Assigns vertical tracking wheels for forward/vertical odometry calculations.</p><hr><h2 id="path-following-configuration" tabindex="-1">Path Following Configuration <a class="header-anchor" href="#path-following-configuration" aria-label="Permalink to &quot;Path Following Configuration&quot;">​</a></h2><p>These settings control how the Pure Pursuit and Boomerang algorithms process paths.</p><h3 id="odom-look-ahead-set-double-distance" tabindex="-1"><code>odom_look_ahead_set(double distance)</code> <a class="header-anchor" href="#odom-look-ahead-set-double-distance" aria-label="Permalink to &quot;`odom_look_ahead_set(double distance)`&quot;">​</a></h3><p>Sets the &quot;virtual carrot&quot; distance for the robot to follow on a path. (Default: <code>7.0</code>).</p><h3 id="odom-path-spacing-set-double-spacing" tabindex="-1"><code>odom_path_spacing_set(double spacing)</code> <a class="header-anchor" href="#odom-path-spacing-set-double-spacing" aria-label="Permalink to &quot;`odom_path_spacing_set(double spacing)`&quot;">​</a></h3><p>Sets the interval at which points are injected into a sparse path. (Default: <code>0.5</code>).</p><h3 id="odom-path-smooth-constants-set-double-weight-smooth-double-weight-data-double-tolerance" tabindex="-1"><code>odom_path_smooth_constants_set(double weight_smooth, double weight_data, double tolerance)</code> <a class="header-anchor" href="#odom-path-smooth-constants-set-double-weight-smooth-double-weight-data-double-tolerance" aria-label="Permalink to &quot;`odom_path_smooth_constants_set(double weight_smooth, double weight_data, double tolerance)`&quot;">​</a></h3><p>Configures the gradient descent smoother for path generation.</p><ul><li><strong>weight_smooth</strong>: How much to curve the points.</li><li><strong>weight_data</strong>: How much to stick to the original waypoints.</li></ul><hr><h2 id="sensors-state" tabindex="-1">Sensors &amp; State <a class="header-anchor" href="#sensors-state" aria-label="Permalink to &quot;Sensors &amp; State&quot;">​</a></h2><h3 id="drive-imu-get" tabindex="-1"><code>drive_imu_get()</code> <a class="header-anchor" href="#drive-imu-get" aria-label="Permalink to &quot;`drive_imu_get()`&quot;">​</a></h3><p>Returns the raw rotation of the inertial sensor.</p><h3 id="drive-sensor-left-drive-sensor-right" tabindex="-1"><code>drive_sensor_left()</code> / <code>drive_sensor_right()</code> <a class="header-anchor" href="#drive-sensor-left-drive-sensor-right" aria-label="Permalink to &quot;`drive_sensor_left()` / `drive_sensor_right()`&quot;">​</a></h3><p>Returns the raw encoder travel in inches for the left and right motor banks.</p>',34)])])}const g=o(i,[["render",s]]);export{m as __pageData,g as default};
